#!/usr/bin/env python3
"""
validate-gkq.py — Round-trip validator for GKQ v2 files.

Two modes:

  1) HF-reference mode: provide --reference-model (an HF id). Loads the same
     model the encoder consumed, compares each spectral tensor's
     dequant-reconstruction against the HF original by Frobenius rel-error,
     and byte-compares each dense tensor.

  2) Self-check mode: --self-check. Reads the GKQ v2 file, verifies all
     spectral blocks reconstruct to sane shapes, all dense blocks have the
     advertised byte length, and round-trips the delta codec on the raw
     bytes. Useful when no HF download is possible.

Exit code 0 on pass, 1 on any failure.
"""

from __future__ import annotations

import argparse
import re
import sys
from pathlib import Path
from typing import Dict, List, Optional

import numpy as np

_HERE = Path(__file__).resolve().parent
sys.path.insert(0, str(_HERE))
import gkq_v2_format as gkq  # noqa: E402

# Reuse the mapping from the encoder.
import importlib.util  # noqa: E402

_enc_spec = importlib.util.spec_from_file_location("_enc", str(_HERE / "encode-real-model.py"))
_enc = importlib.util.module_from_spec(_enc_spec)
_enc_spec.loader.exec_module(_enc)
map_tensor_name = _enc.map_tensor_name


def _flatten_dense_for_compare(arr: np.ndarray) -> np.ndarray:
    return np.ascontiguousarray(arr).ravel()


def validate_against_hf(gkq_path: str, hf_model: str, tolerance: float, max_layers: Optional[int]) -> bool:
    try:
        import torch
        from transformers import AutoModelForCausalLM
    except Exception as e:
        print(f"ERROR: transformers/torch not available: {e}", file=sys.stderr)
        return False

    print(f"[validate] reading GKQ file: {gkq_path}")
    parsed = gkq.read_file(gkq_path)
    header = parsed["header"]
    print(f"[validate] header: model={header['model_name']} arch={header['arch']} "
          f"spectral={header['num_spectral']} dense={header['num_dense']}")

    print(f"[validate] loading HF reference: {hf_model}")
    model = AutoModelForCausalLM.from_pretrained(
        hf_model, torch_dtype=torch.float32, device_map="cpu", low_cpu_mem_usage=True
    )
    state = dict(model.state_dict().items())
    # Build canonical → original tensor map.
    canonical_to_orig: Dict[str, np.ndarray] = {}
    for hf_name, tensor in state.items():
        mapped = map_tensor_name(hf_name, max_layers)
        if mapped is None:
            continue
        canonical, _ = mapped
        t = tensor.detach().cpu()
        if t.dtype == torch.bfloat16:
            t = t.to(torch.float32)
        canonical_to_orig[canonical] = t.numpy()

    # Tied embeddings → ensure output.weight has the embed bytes.
    if "output.weight" not in canonical_to_orig and "token_embd.weight" in canonical_to_orig:
        if bool(getattr(model.config, "tie_word_embeddings", False)):
            canonical_to_orig["output.weight"] = canonical_to_orig["token_embd.weight"]

    failures: List[str] = []
    warnings: List[str] = []
    # Per-spec: at rank-64 we expect <=0.10 typical; warn (don't fail) above 0.20.
    HARD_WARN_THRESHOLD = 0.20
    errors: List[Tuple[str, float]] = []  # (name, rel_err) for all spectral blocks

    for block in parsed["spectral"]:
        name = block["name"]
        orig = canonical_to_orig.get(name)
        if orig is None:
            failures.append(f"spectral {name}: no HF reference found")
            continue
        recon = gkq.reconstruct_spectral(block).astype(np.float32)
        orig32 = np.ascontiguousarray(orig, dtype=np.float32)
        if recon.shape != orig32.shape:
            failures.append(f"spectral {name}: shape {recon.shape} vs {orig32.shape}")
            continue
        denom = float(np.linalg.norm(orig32, "fro")) + 1e-12
        rel = float(np.linalg.norm(orig32 - recon, "fro") / denom)
        errors.append((name, rel))
        if rel <= tolerance:
            status = "OK  "
        elif rel <= HARD_WARN_THRESHOLD:
            status = "SOFT"  # over tolerance but still in soft band
        else:
            status = "WARN"
        print(f"  [{status}] spectral {name:36s} rank={block['rank']:3d} rel_err={rel:.4f}")
        if rel > HARD_WARN_THRESHOLD:
            warnings.append(f"spectral {name}: rel_err={rel:.4f} > soft={HARD_WARN_THRESHOLD}")

    for block in parsed["dense"]:
        name = block["name"]
        if block.get("is_alias"):
            tgt = block.get("alias_target", "?")
            print(f"  [OK ] dense    {name:36s} alias→{tgt}")
            continue
        orig = canonical_to_orig.get(name)
        if orig is None:
            failures.append(f"dense {name}: no HF reference found")
            continue
        if block["array"] is None:
            # Pre-quantized payload: byte-compare original-cast bytes is not meaningful.
            print(f"  [SKIP] dense {name:36s} dtype={block['dtype_name']} (raw quantized; byte-cmp skipped)")
            continue
        recon = block["array"]
        # The encoder may have stored fp16; cast original to match dtype.
        try:
            orig_cast = orig.astype(recon.dtype)
        except Exception:
            orig_cast = orig
        if recon.shape != orig_cast.shape:
            failures.append(f"dense {name}: shape {recon.shape} vs {orig_cast.shape}")
            continue
        exact = recon.tobytes() == orig_cast.tobytes()
        if exact:
            print(f"  [OK ] dense    {name:36s} bytes match ({recon.nbytes:,} B, {block['dtype_name']})")
        else:
            # Allow tiny f16 rounding when original is f32 cast to f16.
            diff = float(np.max(np.abs(recon.astype(np.float32) - orig_cast.astype(np.float32))))
            print(f"  [WARN] dense    {name:36s} bytes differ (max |Δ|={diff:.6f}, {block['dtype_name']})")
            if diff > 1e-3:
                failures.append(f"dense {name}: max |Δ|={diff:.6f}")

    # Summary stats.
    if errors:
        errs_only = sorted([e for _, e in errors])
        worst3 = sorted(errors, key=lambda t: -t[1])[:3]
        median = errs_only[len(errs_only) // 2]
        mean = sum(errs_only) / len(errs_only)
        print(f"[validate] spectral rel_err: median={median:.4f} mean={mean:.4f} "
              f"min={errs_only[0]:.4f} max={errs_only[-1]:.4f}")
        print(f"[validate] worst-3:")
        for n, e in worst3:
            print(f"  - {e:.4f}  {n}")

    over_tol = [e for _, e in errors if e > tolerance]
    if over_tol:
        print(f"[validate] {len(over_tol)}/{len(errors)} spectral tensors over tolerance "
              f"({tolerance}); {len(warnings)} of those over soft threshold "
              f"({HARD_WARN_THRESHOLD}).")

    if failures:
        print(f"[validate] {len(failures)} HARD failures:")
        for f in failures[:20]:
            print(f"  - {f}")
        return False
    if warnings:
        print(f"[validate] {len(warnings)} soft warnings (rel_err > {HARD_WARN_THRESHOLD}); not failing.")
    print(f"[validate] structural checks passed (tolerance={tolerance}, soft={HARD_WARN_THRESHOLD})")
    return True


def validate_self_check(gkq_path: str, tolerance: float) -> bool:
    print(f"[self-check] reading GKQ file: {gkq_path}")
    parsed = gkq.read_file(gkq_path)
    header = parsed["header"]
    print(f"[self-check] header: model={header['model_name']} arch={header['arch']} "
          f"spectral={header['num_spectral']} dense={header['num_dense']}")
    failures: List[str] = []

    for block in parsed["spectral"]:
        name = block["name"]
        d_out = block["d_out"]
        d_in = block["d_in"]
        rank = block["rank"]
        if block["u_q8"].shape != (d_out, rank):
            failures.append(f"spectral {name}: u_q8 shape {block['u_q8'].shape} != ({d_out},{rank})")
        if block["v_q8"].shape != (rank, d_in):
            failures.append(f"spectral {name}: v_q8 shape {block['v_q8'].shape} != ({rank},{d_in})")
        if block["sigma_q8"].shape != (rank,):
            failures.append(f"spectral {name}: sigma_q8 shape {block['sigma_q8'].shape} != ({rank},)")
        recon = gkq.reconstruct_spectral(block)
        if recon.shape != (d_out, d_in):
            failures.append(f"spectral {name}: recon shape {recon.shape} != ({d_out},{d_in})")
        if not np.all(np.isfinite(recon)):
            failures.append(f"spectral {name}: non-finite values in reconstruction")
        print(f"  [OK ] spectral {name:36s} shape=({d_out},{d_in}) rank={rank} recon_max={np.max(np.abs(recon)):.4f}")

    for block in parsed["dense"]:
        name = block["name"]
        if block.get("is_alias"):
            tgt = block.get("alias_target", "?")
            print(f"  [OK ] dense    {name:36s} alias→{tgt}")
            continue
        expected_bytes = int(np.prod(block["dims"]) * (4 if block["dtype_code"] == gkq.DTYPE_F32
                                                         else 2 if block["dtype_code"] == gkq.DTYPE_F16
                                                         else 0))
        if expected_bytes and len(block["raw"]) != expected_bytes:
            failures.append(f"dense {name}: raw len {len(block['raw'])} != expected {expected_bytes}")
        print(f"  [OK ] dense    {name:36s} dims={tuple(block['dims'])} dtype={block['dtype_name']} bytes={len(block['raw']):,}")

    # Delta codec round-trip on a chunk of one spectral's u_q8.
    if parsed["spectral"]:
        u = parsed["spectral"][0]["u_q8"].ravel()
        re_enc = gkq.delta_encode(u)
        re_dec = gkq.delta_decode(re_enc)
        if not np.array_equal(u, re_dec):
            failures.append("delta codec round-trip on first spectral u_q8 failed")
        else:
            print("  [OK ] delta codec round-trip on first spectral block")

    if failures:
        print(f"[self-check] {len(failures)} failures:")
        for f in failures[:20]:
            print(f"  - {f}")
        return False
    print(f"[self-check] all structural checks passed")
    return True


def parse_args(argv=None):
    p = argparse.ArgumentParser(description="Validate a GKQ v2 file.")
    p.add_argument("--gkq", required=True, help="Path to GKQ v2 .knot file")
    p.add_argument("--reference-model", default=None, help="HF model id to compare against")
    p.add_argument("--tolerance", type=float, default=0.10,
                   help="Frobenius rel-error tolerance for spectral reconstructions")
    p.add_argument("--max-layers", type=int, default=None,
                   help="Restrict reference comparison to first N layers (must match encoder)")
    p.add_argument("--self-check", action="store_true",
                   help="Skip HF reference; just verify structural integrity")
    return p.parse_args(argv)


def main(argv=None) -> int:
    args = parse_args(argv)
    if args.self_check or args.reference_model is None:
        ok = validate_self_check(args.gkq, args.tolerance)
    else:
        ok = validate_against_hf(args.gkq, args.reference_model, args.tolerance, args.max_layers)
    return 0 if ok else 1


if __name__ == "__main__":
    raise SystemExit(main())
